    >
      <div class="absolute inset-0 bg-slate-950/20 backdrop-blur-[1px]"></div>
      <div class="relative max-w-4xl mx-auto px-4 space-y-4">
        <h1 class="text-3xl sm:text-4xl font-extrabold tracking-tight">
