          담당 부서에서 신속히 안내해 드리겠습니다.
        </p>
      </div>
    </section>

    <!-- Inquiry Container -->
    <section class="py-16 max-w-4xl mx-auto px-4 sm:px-6">
      <div
        class="bg-white dark:bg-slate-900 border border-slate-200/60 dark:border-slate-800/80 rounded-3xl p-8 sm:p-12 shadow-sm"
      >
        <h2 class="text-xl font-bold text-slate-900 dark:text-white mb-6">
          문의 및 견적 신청서
        </h2>

        <form @submit.prevent="handleSubmit" class="space-y-6">
          <div class="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <!-- Company Name -->
            <div class="space-y-2">
              <label
                for="company"
                class="block text-sm font-semibold text-slate-700 dark:text-slate-300"
                >회사명 <span class="text-red-500">*</span></label
              >
              <input
                id="company"
                v-model="form.company"
                type="text"
                required
                placeholder="예: 오리온테크"
                class="w-full px-4 py-3 rounded-xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 text-slate-900 dark:text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent text-sm transition-all"
              />
            </div>

            <!-- Name -->
            <div class="space-y-2">
              <label
                for="name"
                class="block text-sm font-semibold text-slate-700 dark:text-slate-300"
                >담당자명 <span class="text-red-500">*</span></label
              >
              <input
                id="name"
                v-model="form.name"
                type="text"
                required
                placeholder="예: 홍길동"
                class="w-full px-4 py-3 rounded-xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 text-slate-900 dark:text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent text-sm transition-all"
              />
            </div>
          </div>

          <div class="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <!-- Email -->
            <div class="space-y-2">
              <label
                for="email"
                class="block text-sm font-semibold text-slate-700 dark:text-slate-300"
                >이메일 주소 <span class="text-red-500">*</span></label
              >
              <input
                id="email"
                v-model="form.email"
                type="email"
                required
                placeholder="example@domain.com"
                class="w-full px-4 py-3 rounded-xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 text-slate-900 dark:text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent text-sm transition-all"
              />
            </div>

            <!-- Phone -->
            <div class="space-y-2">
              <label
                for="phone"
                class="block text-sm font-semibold text-slate-700 dark:text-slate-300"
                >연락처 <span class="text-red-500">*</span></label
              >
              <input
                id="phone"
                v-model="form.phone"
                type="tel"
                required
                placeholder="010-0000-0000"
                class="w-full px-4 py-3 rounded-xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 text-slate-900 dark:text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent text-sm transition-all"
              />
            </div>
          </div>

          <!-- Subject -->
          <div class="space-y-2">
            <label
              for="subject"
              class="block text-sm font-semibold text-slate-700 dark:text-slate-300"
              >문의 제목 <span class="text-red-500">*</span></label
            >
            <input
              id="subject"
              v-model="form.subject"
              type="text"
              required
              placeholder="문의글의 제목을 적어주세요."
              class="w-full px-4 py-3 rounded-xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 text-slate-900 dark:text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent text-sm transition-all"
            />
          </div>

          <!-- Content -->
          <div class="space-y-2">
            <label
              for="message"
              class="block text-sm font-semibold text-slate-700 dark:text-slate-300"
              >상세 문의 내용 <span class="text-red-500">*</span></label
            >
            <textarea
              id="message"
              v-model="form.message"
              required
              rows="6"
              placeholder="구체적인 제품 번호, 전압 조건, 환경 스펙 및 구매 예정 수량 등을 상세히 작성해 주시면 조속한 피드백이 가능합니다."
              class="w-full px-4 py-3 rounded-xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 text-slate-900 dark:text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent text-sm transition-all resize-none"
            ></textarea>
          </div>

          <!-- File Attachment -->
          <div class="space-y-2">
            <label
              class="block text-sm font-semibold text-slate-700 dark:text-slate-300"
              >첨부파일 (회로도/사양서 도면 등)</label
            >
            <div class="flex items-center justify-center w-full">
              <label
                for="file-upload"
                class="flex flex-col items-center justify-center w-full h-32 border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-2xl cursor-pointer bg-slate-50 dark:bg-slate-950 hover:bg-slate-100 dark:hover:bg-slate-900 transition-colors"
              >
                <div
                  class="flex flex-col items-center justify-center pt-5 pb-6"
                >
                  <UploadCloud class="w-8 h-8 text-slate-400 mb-2" />
                  <p class="text-xs text-slate-500 dark:text-slate-400">
                    <span class="font-semibold text-primary-500"
                      >클릭하여 파일 선택</span
                    >
                    또는 드래그 앤 드롭
                  </p>
                  <p class="text-[10px] text-slate-400 mt-1">
                    PDF, ZIP, PNG, JPG (최대 10MB)
                  </p>
                </div>
                <input
                  id="file-upload"
                  type="file"
                  class="hidden"
                  @change="handleFileChange"
                  accept=".pdf,.zip,.png,.jpg,.jpeg"
                />
              </label>
            </div>
            <!-- File Preview Info -->
            <div
              v-if="selectedFile"
              class="flex items-center justify-between p-3 bg-primary-50 dark:bg-primary-950/20 border border-primary-100 dark:border-primary-950/50 rounded-xl text-xs"
            >
              <span
                class="font-medium text-slate-700 dark:text-slate-300 truncate max-w-md"
                >{{ selectedFile.name }} ({{
                  formatFileSize(selectedFile.size)
                }})</span
              >
              <button
                type="button"
                @click="removeFile"
                class="text-red-500 hover:text-red-600 font-bold"
              >
                삭제
              </button>
            </div>
          </div>

          <!-- Info Agreement -->
          <div
            class="flex items-start gap-3 p-4 bg-slate-50 dark:bg-slate-950 rounded-2xl border border-slate-100 dark:border-slate-800"
          >
            <input
              id="agreement"
              type="checkbox"
              required
              v-model="privacyChecked"
              class="mt-1 w-4 h-4 rounded text-primary-600 focus:ring-primary-500 border-slate-300"
            />
            <label
              for="agreement"
              class="text-xs text-slate-500 dark:text-slate-400 leading-normal cursor-pointer select-none"
            >
              (필수) 개인정보 수집 및 이용 동의: 문의하신 내역 확인 및 정확한
              기술 상담 응대를 위해 회사명, 담당자명, 이메일, 연락처 정보를
              수집하고 관련 상담 완료 시까지 보유하는 것에 동의합니다.
            </label>
          </div>

          <!-- Submit Button -->
          <button
            type="submit"
            :disabled="submitting"
            class="w-full py-4 text-base font-semibold text-white bg-primary-600 hover:bg-primary-500 disabled:bg-slate-400 rounded-xl transition-all shadow-lg shadow-primary-500/10 flex items-center justify-center gap-2"
          >
            <Loader2 v-if="submitting" class="w-5 h-5 animate-spin" />
            <span>{{
              submitting
                ? "문의를 송신하고 있습니다..."
                : "문의하기 및 견적 요청 제출"
            }}</span>
          </button>
        </form>

        <!-- Status Notifications -->
        <Transition
          enter-active-class="transition duration-300 ease-out"
          enter-from-class="opacity-0 translate-y-4"
          enter-to-class="opacity-100 translate-y-0"
        >
          <div
            v-if="statusMessage"
            class="mt-6 p-4 rounded-xl text-center text-sm font-semibold"
            :class="[
              statusType === 'success'
                ? 'bg-emerald-50 text-emerald-800 border border-emerald-200 dark:bg-emerald-950/30 dark:text-emerald-400 dark:border-emerald-950/50'
                : 'bg-rose-50 text-rose-800 border border-rose-200 dark:bg-rose-950/30 dark:text-rose-400 dark:border-rose-950/50',
            ]"
          >
            {{ statusMessage }}
          </div>
        </Transition>
      </div>
    </section>
  </div>
</template>

<script setup>
import { ref, onMounted } from "vue";
import { useRoute } from "vue-router";
import { UploadCloud, Loader2 } from "lucide-vue-next";

const route = useRoute();
const submitting = ref(false);
const privacyChecked = ref(false);
const selectedFile = ref(null);
const statusMessage = ref("");
const statusType = ref("success");

const form = ref({
  company: "",
  name: "",
  email: "",
  phone: "",
  subject: "",
  message: "",
});

onMounted(() => {
  if (route.query.model) {
    form.value.subject = `[제품문의] ${route.query.model} 모델 견적 및 사양 문의`;
    form.value.message = `제품 모델: ${route.query.model}\n\n제품 사양서 요청 및 수량별 견적 확인을 요청합니다.\n내용:`;
  }
});

const handleFileChange = (e) => {
  const files = e.target.files;
  if (files && files[0]) {
    const file = files[0];
    if (file.size > 10 * 1024 * 1024) {
      alert("파일 크기는 최대 10MB를 초과할 수 없습니다.");
      return;
    }
    selectedFile.value = file;
  }
};

const removeFile = () => {
  selectedFile.value = null;
};

const formatFileSize = (bytes) => {
  if (bytes === 0) return "0 Bytes";
  const k = 1024;
  const sizes = ["Bytes", "KB", "MB"];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + " " + sizes[i];
};

const handleSubmit = async () => {
  if (!privacyChecked.value) {
    alert("개인정보 수집 및 이용에 동의하셔야 문의 접수가 가능합니다.");
    return;
  }

  submitting.value = true;
  statusMessage.value = "";

  try {
    // We use FormData to handle file uploads
    const formData = new FormData();
    formData.append("company", form.value.company);
    formData.append("name", form.value.name);
    formData.append("email", form.value.email);
    formData.append("phone", form.value.phone);
    formData.append("subject", form.value.subject);
    formData.append("message", form.value.message);
    if (selectedFile.value) {
      formData.append("attachment", selectedFile.value);
    }

    const response = await $fetch("/api/inquiry", {
      method: "POST",
      body: formData,
    });

    if (response.success) {
      statusType.value = "success";
      statusMessage.value =
        "문의가 정상적으로 접수되었습니다. 이메일을 통해 관리자에게 전송되었습니다.";
      // Reset form
      form.value = {
        company: "",
        name: "",
        email: "",
        phone: "",
        subject: "",
        message: "",
      };
      selectedFile.value = null;
      privacyChecked.value = false;
    } else {
      throw new Error(response.message || "접수 도중 오류가 발생했습니다.");
    }
  } catch (error) {
    statusType.value = "error";
    statusMessage.value = `전송 실패: ${error.message || "서버 통신 오류가 발생했습니다."}`;
  } finally {
    submitting.value = false;
  }
};
</script>
